from mcp.server.fastmcp import FastMCP

mcp = FastMCP("inventario-server")

@mcp.tool()
def consultar_stock(sku: str) -> str:
    """Devuelve el stock disponible para un SKU dado. Usala cuando te
    pregunten por disponibilidad de un producto específico."""
    stock = base_de_datos.get(sku, 0)
    return f"El SKU {sku} tiene {stock} unidades disponibles"

if __name__ == "__main__":
    mcp.run()

@mcp.resource("config://politica-devoluciones")
def politica_devoluciones() -> str:
    return open("politica.md").read()

# resource template: la parte {cliente_id} se completa al leerlo
