async def call_with_token_refresh(mcp_client, operation, *args):
    try:
        return await mcp_client.call_tool(operation, *args)
    except AuthorizationError as e:
        if e.status_code == 401:
            # Refresh antes de reintentar
            new_token = await refresh_oauth_token(mcp_client.refresh_token)
            mcp_client.access_token = new_token
            return await mcp_client.call_tool(operation, *args)  # retry
        raise  # otros errores de autorizacion: propagar
